import React, { useState, useEffect, useCallback } from 'react'; // ✅ Добавь useCallback
import { useAppContext } from '../context/AppContext';
import { api } from '../services/api';
import DashboardHeader from '../components/Dashboard/DashboardHeader';
import KpiCards from '../components/Dashboard/KpiCards';
import RevenueChart from '../components/Dashboard/RevenueChart';
import TopProductsTable from '../components/Dashboard/TopProductsTable';
import ExportButton from '../components/Export/ExportButton';
import Button from '../components/UI/Button';

const Dashboard = () => {
  const { period, logistics } = useAppContext();
  const [dashboardData, setDashboardData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [loadingError, setLoadingError] = useState(null);

  // ✅ Оберни fetchData в useCallback, чтобы она не пересоздавалась каждый раз
  const fetchData = useCallback(async () => {
    setLoading(true);
    setLoadingError(null);
    try {
      const data = await api.getDashboardData(period, logistics);
      setDashboardData(data);
    } catch (error) {
      console.error("Failed to fetch dashboard ", error);
      if (error.status === 404) {
        setDashboardData(null);
      } else {
        setLoadingError(error.message || "Не удалось загрузить данные");
      }
    } finally {
      setLoading(false);
    }
  }, [period, logistics]); // ✅ Зависимости: period и logistics

  const handleSyncAndLoad = useCallback(async () => {
    try {
      await api.triggerSync();
      setTimeout(() => {
        fetchData();
      }, 1000);
    } catch (error) {
      console.error("Failed to trigger sync", error);
      alert("Ошибка синхронизации: " + (error.message || "Неизвестная ошибка"));
    }
  }, [fetchData]); // ✅ Зависимость: fetchData

  useEffect(() => {
    fetchData();
  }, [fetchData]); // ✅ Теперь useEffect зависит от fetchData, обёрнутой в useCallback

  if (loading) {
    return <div className="p-6">Загрузка данных дашборда...</div>;
  }

  if (loadingError) {
    return (
      <div className="p-6 text-center">
        <p className="text-red-600 dark:text-red-400">Ошибка: {loadingError}</p>
        <Button onClick={fetchData} className="mt-4">Повторить попытку</Button>
      </div>
    );
  }

  if (!dashboardData) {
    return (
      <div className="p-6 text-center">
        <h1 className="text-2xl font-bold mb-4">Общий дашборд</h1>
        <p className="text-gray-600 dark:text-gray-400 mb-6">
          Данные отсутствуют. Нажмите кнопку ниже, чтобы синхронизировать данные с Ozon.
        </p>
        <Button onClick={handleSyncAndLoad}>
          🔄 Синхронизировать данные
        </Button>
      </div>
    );
  }

  return (
    <div className="p-6">
      <div className="flex justify-between items-center mb-4">
        <h1 className="text-2xl font-bold">Общий дашборд</h1>
        <ExportButton data={dashboardData} scope="dashboard" period={period} logistics={logistics} />
      </div>
      <DashboardHeader onSync={setDashboardData} />
      <KpiCards data={dashboardData} />
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-6">
        <div className="bg-white dark:bg-gray-800 p-4 rounded-lg shadow">
          <RevenueChart data={dashboardData} />
        </div>
        <div className="bg-white dark:bg-gray-800 p-4 rounded-lg shadow">
          <h2 className="text-lg font-semibold mb-4">ТОП-5 товаров</h2>
          <TopProductsTable data={dashboardData} />
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
